import React, { useState, useEffect } from 'react';
import axios from 'axios';

const MapView = () => {
  const [issues, setIssues] = useState([]);
  const [loading, setLoading] = useState(true);
  const [userLocation, setUserLocation] = useState(null);
  const [mapError, setMapError] = useState('');

  useEffect(() => {
    fetchIssues();
    getUserLocation();
  }, []);

  const fetchIssues = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/issues');
      setIssues(response.data.issues);
    } catch (error) {
      console.error('Error fetching issues:', error);
    } finally {
      setLoading(false);
    }
  };

  const getUserLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setUserLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          });
        },
        (error) => {
          console.error('Error getting location:', error);
          setMapError('Unable to get your location. Map may not work properly.');
        }
      );
    } else {
      setMapError('Geolocation is not supported by your browser.');
    }
  };

  const getTypeIcon = (type) => {
    switch (type) {
      case 'pothole':
        return '🕳️';
      case 'streetlight':
        return '💡';
      case 'water_leakage':
        return '💧';
      case 'garbage_overflow':
        return '🗑️';
      case 'public_property':
        return '🏛️';
      default:
        return '⚠️';
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'pending':
        return '#FCD34D'; // yellow
      case 'in_progress':
        return '#60A5FA'; // blue
      case 'resolved':
        return '#34D399'; // green
      default:
        return '#9CA3AF'; // gray
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="text-lg">Loading map...</div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
      <div className="px-4 py-6 sm:px-0">
        <h1 className="text-3xl font-bold text-gray-900 mb-6">Infrastructure Issues Map</h1>

        {mapError && (
          <div className="bg-yellow-100 border border-yellow-400 text-yellow-700 px-4 py-3 rounded mb-6">
            {mapError}
          </div>
        )}

        {/* Map Container */}
        <div className="bg-white shadow rounded-lg overflow-hidden mb-6">
          <div className="relative h-96 md:h-[600px] bg-gray-200">
            {/* Placeholder for Google Maps */}
            <div className="absolute inset-0 flex items-center justify-center">
              <div className="text-center">
                <div className="text-6xl mb-4">🗺️</div>
                <h2 className="text-xl font-semibold text-gray-700 mb-2">Google Maps Integration</h2>
                <p className="text-gray-600 mb-4">
                  Add your Google Maps API key to display the interactive map
                </p>
                <div className="bg-gray-100 p-4 rounded-lg text-left max-w-md mx-auto">
                  <p className="text-sm text-gray-700">
                    <strong>To enable the map:</strong><br/>
                    1. Get a Google Maps JavaScript API key<br/>
                    2. Add it to the backend .env file<br/>
                    3. Replace this placeholder with the actual map component
                  </p>
                </div>
              </div>
            </div>

            {/* Issue Markers (for demonstration) */}
            {issues.map((issue) => (
              <div
                key={issue._id}
                className="absolute transform -translate-x-1/2 -translate-y-1/2 cursor-pointer group"
                style={{
                  left: `${Math.random() * 80 + 10}%`,
                  top: `${Math.random() * 60 + 20}%`,
                }}
                title={`${issue.title} - ${issue.status}`}
              >
                <div
                  className="w-8 h-8 rounded-full flex items-center justify-center text-lg shadow-lg border-2 border-white"
                  style={{ backgroundColor: getStatusColor(issue.status) }}
                >
                  {getTypeIcon(issue.type)}
                </div>
                <div className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-2 hidden group-hover:block z-10">
                  <div className="bg-gray-900 text-white text-xs rounded py-1 px-2 whitespace-nowrap">
                    <div className="font-semibold">{issue.title}</div>
                    <div>{issue.status.replace('_', ' ')}</div>
                    <div className="text-gray-300">by {issue.reportedBy.name}</div>
                  </div>
                </div>
              </div>
            ))}

            {/* User Location Marker */}
            {userLocation && (
              <div
                className="absolute transform -translate-x-1/2 -translate-y-1/2"
                style={{
                  left: '50%',
                  top: '50%',
                }}
                title="Your Location"
              >
                <div className="w-4 h-4 bg-blue-500 rounded-full border-2 border-white shadow-lg"></div>
                <div className="absolute inset-0 bg-blue-500 rounded-full animate-ping"></div>
              </div>
            )}
          </div>
        </div>

        {/* Issues List */}
        <div className="bg-white shadow rounded-lg p-4">
          <h2 className="text-lg font-semibold text-gray-900 mb-4">Reported Issues ({issues.length})</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {issues.map((issue) => (
              <div key={issue._id} className="border border-gray-200 rounded-lg p-3">
                <div className="flex items-start space-x-3">
                  <div
                    className="w-10 h-10 rounded-full flex items-center justify-center text-lg flex-shrink-0"
                    style={{ backgroundColor: getStatusColor(issue.status) }}
                  >
                    {getTypeIcon(issue.type)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className="text-sm font-medium text-gray-900 truncate">{issue.title}</h3>
                    <p className="text-xs text-gray-500">{issue.location.address}</p>
                    <div className="flex items-center mt-1">
                      <span className={`inline-flex items-center px-2 py-0.5 rounded text-xs font-medium ${
                        issue.status === 'pending' ? 'bg-yellow-100 text-yellow-800' :
                        issue.status === 'in_progress' ? 'bg-blue-100 text-blue-800' :
                        'bg-green-100 text-green-800'
                      }`}>
                        {issue.status.replace('_', ' ')}
                      </span>
                      <span className="ml-2 text-xs text-gray-400">
                        {new Date(issue.createdAt).toLocaleDateString()}
                      </span>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {issues.length === 0 && (
          <div className="text-center py-12">
            <div className="text-gray-500 text-lg">No issues reported yet</div>
            <p className="text-gray-400 mt-2">Be the first to report an infrastructure issue!</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default MapView;
